import { expect, test } from "@playwright/test";

import {
  dumpStuckState,
  driveRunToWin,
  resolveCampaignSeed,
  seedToTitleNowMs
} from "./browser-bot";

const campaignSeed = resolveCampaignSeed();

test.describe("full-game browser-clear campaign", () => {
  test.beforeEach(async ({ page }) => {
    await page.addInitScript((nowMs) => {
      window.localStorage.clear();
      Date.now = () => nowMs;
    }, seedToTitleNowMs(campaignSeed));
  });

  test(`clears floors 1–12 to WIN for seed ${campaignSeed}`, async ({
    page
  }) => {
    const state = page.getByTestId("game-state");

    try {
      await page.goto(`/?seed=${encodeURIComponent(campaignSeed)}`);
      await expect(state).toHaveAttribute("data-screen", "title");
      await expect(page.getByTestId("title-seed")).toContainText(campaignSeed);

      await page.getByTestId("new-run-button").click();
      await expect(state).toHaveAttribute("data-screen", "playing");
      await expect(state).toHaveAttribute("data-depth", "1");
      await expect(state).toHaveAttribute("data-turn", "0");

      await driveRunToWin(page, { seed: campaignSeed });

      await expect(state).toHaveAttribute("data-screen", "summary");
      await expect(state).toHaveAttribute("data-terminal-status", "WIN");
      await expect(page.getByTestId("summary-screen")).toBeVisible();
      await expect(page.getByTestId("dungeon-diary")).toHaveAttribute(
        "data-diary-mode",
        "final"
      );

      await page.getByTestId("run-index-button").click();
      await expect(state).toHaveAttribute("data-screen", "run-index");
      await expect(page.getByTestId("run-index")).toBeVisible();
      await expect(page.getByTestId("run-index-entry")).toHaveCount(1);
      await expect(page.getByTestId("run-index-entry").first()).toHaveAttribute(
        "data-outcome",
        "victory"
      );
    } catch (error) {
      await dumpStuckState(
        page,
        `full-clear spec failure: ${
          error instanceof Error ? error.message : String(error)
        }`
      );
      throw error;
    }
  });
});

test.describe("determinism note", () => {
  test.skip(
    process.env.FULLCLEAR_DETERMINISM !== "1",
    "set FULLCLEAR_DETERMINISM=1 to run paired determinism check"
  );

  test("same seed reaches the same terminal turn twice", async ({
    browser
  }) => {
    const runOnce = async (): Promise<number> => {
      const context = await browser.newContext();
      const page = await context.newPage();
      await page.addInitScript((nowMs) => {
        Date.now = () => nowMs;
      }, seedToTitleNowMs(campaignSeed));

      const state = page.getByTestId("game-state");
      await page.goto(`/?seed=${encodeURIComponent(campaignSeed)}`);
      await page.getByTestId("new-run-button").click();
      await driveRunToWin(page, { seed: campaignSeed });
      const turns = Number.parseInt(
        (await state.getAttribute("data-turn")) ?? "-1",
        10
      );
      await context.close();
      return turns;
    };

    const first = await runOnce();
    const second = await runOnce();
    expect(second).toBe(first);
  });
});

import { expect, type Locator, type Page } from "@playwright/test";
import fs from "node:fs/promises";
import path from "node:path";

export const MAX_TURN_CAP = 3_000;
export const FINAL_DEPTH = 12;
const FLOOR_SETTLE_TIMEOUT_MS = 130_000;
const TELEMETRY_INTERVAL_TURNS = 250;
const PINNED_POSITION_TURNS = 10;
const NO_PROGRESS_REPEAT_CAP = 24;

export type GridCell = {
  readonly x: number;
  readonly y: number;
  readonly glyph: string;
  readonly terrain: string;
  readonly fog: "visible" | "remembered" | "unseen";
  readonly layer: string;
  readonly featureKind: string;
  readonly featureId: string;
  readonly hasItem: boolean;
};

export type HudSnapshot = {
  readonly hpCurrent: number;
  readonly hpMax: number;
  readonly hpRatio: number;
};

export type ShellSnapshot = {
  readonly screen: string;
  readonly depth: number;
  readonly turn: number;
  readonly terminalStatus: string;
  readonly inputLocked: boolean;
  readonly panelMode: string;
  readonly diaryOpen: boolean;
  readonly transitionPhase: string;
};

export type BotDiagnosis = {
  readonly reason: string;
  readonly shell: ShellSnapshot;
  readonly hud: HudSnapshot | null;
  readonly player: { readonly x: number; readonly y: number } | null;
  readonly gameStateAttributes: Record<string, string>;
  readonly recentLogLines: readonly string[];
};

type Direction =
  | "north"
  | "south"
  | "east"
  | "west"
  | "northeast"
  | "northwest"
  | "southeast"
  | "southwest";

type GridPosition = {
  readonly x: number;
  readonly y: number;
};

type BotOptions = {
  readonly seed?: string;
  readonly log?: (message: string) => void;
};

type BotPolicyState = {
  readonly visitedByDepth: Map<number, Set<string>>;
  readonly rng: () => number;
  readonly log: (message: string) => void;
  lastMoveDirection: Direction | null;
};

const DIRECTION_KEYS: Record<Direction, string> = {
  north: "ArrowUp",
  south: "ArrowDown",
  west: "ArrowLeft",
  east: "ArrowRight",
  northwest: "y",
  northeast: "u",
  southwest: "b",
  southeast: "n"
};

const DIRECTION_DELTAS: Record<Direction, GridPosition> = {
  north: { x: 0, y: -1 },
  south: { x: 0, y: 1 },
  west: { x: -1, y: 0 },
  east: { x: 1, y: 0 },
  northwest: { x: -1, y: -1 },
  northeast: { x: 1, y: -1 },
  southwest: { x: -1, y: 1 },
  southeast: { x: 1, y: 1 }
};

const DIRECTIONS: readonly Direction[] = [
  "north",
  "northeast",
  "east",
  "southeast",
  "south",
  "southwest",
  "west",
  "northwest"
];

const BLOCKED_TERRAIN = new Set(["wall", ""]);

export async function driveRunToWin(
  page: Page,
  options: BotOptions = {}
): Promise<void> {
  const state = page.getByTestId("game-state");
  const policyState: BotPolicyState = {
    visitedByDepth: new Map<number, Set<string>>(),
    rng: seededRandom(options.seed ?? resolveCampaignSeed()),
    log: options.log ?? console.log,
    lastMoveDirection: null
  };
  let turns = 0;
  let lastSignature = "";
  let stuckRepeats = 0;
  let unchangedPositionTurns = 0;

  while (turns < MAX_TURN_CAP) {
    await settleUi(page);

    const shell = await readShellSnapshot(state);
    if (shell.screen !== "playing") {
      if (shell.terminalStatus === "WIN") {
        return;
      }
      await dumpStuckState(page, "left playing screen before WIN");
      throw new BotFailure("left playing screen before WIN", {
        shell,
        hud: await readHudSnapshot(page),
        player: null,
        gameStateAttributes: await readGameStateAttributes(page),
        recentLogLines: await readRecentLogLines(page),
        reason: `screen=${shell.screen} terminal=${shell.terminalStatus}`
      });
    }

    if (shell.terminalStatus === "WIN") {
      return;
    }

    const beforeTurn = shell.turn;
    const beforePosition = await readPlayerPosition(page);
    const key = await choosePolicyKey(page, shell, policyState);
    const keyDirection = directionForKey(key);
    if (key === null) {
      await waitForUiFrame(page);
    } else {
      await pressGameplayKey(page, key);
    }

    const after = await readShellSnapshot(state);
    if (after.turn === beforeTurn && after.screen === "playing") {
      const signature = await progressSignature(page, after);
      stuckRepeats = signature === lastSignature ? stuckRepeats + 1 : 0;
      lastSignature = signature;
      if (stuckRepeats >= NO_PROGRESS_REPEAT_CAP) {
        await dumpStuckState(
          page,
          `no turn progress for ${NO_PROGRESS_REPEAT_CAP} identical states`
        );
        throw new Error("bot stuck: no turn progress");
      }
      continue;
    }

    stuckRepeats = 0;
    lastSignature = "";
    turns += 1;
    if (keyDirection !== null) {
      policyState.lastMoveDirection = keyDirection;
    }

    const afterPosition = await readPlayerPosition(page);
    unchangedPositionTurns =
      beforePosition !== null &&
      afterPosition !== null &&
      samePosition(beforePosition, afterPosition)
        ? unchangedPositionTurns + 1
        : 0;

    if (
      unchangedPositionTurns >= PINNED_POSITION_TURNS &&
      afterPosition !== null &&
      after.screen === "playing"
    ) {
      await breakPinnedLoop(page, after, afterPosition, policyState);
      unchangedPositionTurns = 0;
    }

    if (turns % TELEMETRY_INTERVAL_TURNS === 0) {
      await logTelemetry(page, after, policyState);
    }
  }

  const shell = await readShellSnapshot(state);
  await dumpStuckState(
    page,
    `turn cap ${MAX_TURN_CAP} exceeded at depth ${shell.depth}`
  );
  throw new Error(
    `bot exceeded turn cap (${MAX_TURN_CAP}) at depth ${shell.depth}`
  );
}

export async function dumpStuckState(
  page: Page,
  reason: string
): Promise<void> {
  const dir = path.join("test-results", "full-clear-stuck");
  await fs.mkdir(dir, { recursive: true });
  const stamp = Date.now();
  const shell = await readShellSnapshot(page.getByTestId("game-state"));
  const hud = await readHudSnapshot(page);
  const player = await readPlayerPosition(page);
  const gameStateAttributes = await readGameStateAttributes(page);
  const recentLogLines = await readRecentLogLines(page);

  await page.screenshot({
    path: path.join(dir, `stuck-${stamp}.png`),
    fullPage: true
  });

  const payload = {
    reason,
    shell,
    hud,
    player,
    gameStateAttributes,
    recentLogLines
  };

  await fs.writeFile(
    path.join(dir, `stuck-${stamp}.json`),
    `${JSON.stringify(payload, null, 2)}\n`,
    "utf8"
  );
}

async function settleUi(page: Page): Promise<void> {
  const state = page.getByTestId("game-state");
  const shell = await readShellSnapshot(state);

  if (shell.screen !== "playing") {
    return;
  }

  const transition = page.getByTestId("transition-overlay");
  if (await transition.isVisible().catch(() => false)) {
    const skipEnabled = await transition.getAttribute("data-skip-enabled");
    if (skipEnabled === "true") {
      await page.keyboard.press("Space");
    }
    await expect(state).toHaveAttribute("data-input-locked", "false", {
      timeout: FLOOR_SETTLE_TIMEOUT_MS
    });
    return;
  }

  if (shell.panelMode === "dialogue") {
    await page.keyboard.press("Escape");
    await expect(state).toHaveAttribute("data-panel-mode", "inspect");
    return;
  }

  if (shell.panelMode !== "inspect") {
    await page.keyboard.press("Escape");
    await expect(state).toHaveAttribute("data-panel-mode", "inspect");
    return;
  }

