const terrainAt = (
  grid: ReturnType<typeof gridFromState>,
  width: number,
  height: number,
  x: number,
  y: number,
): string => {
  if (
    grid === null ||
    grid.width !== width ||
    grid.height !== height
  ) {
    return "";
  }

  const tile = grid.tiles[y * width + x];
  return typeof tile?.terrain === "string" ? tile.terrain : "";
};

const overlayMarkersByCell = (
  markers: readonly GridOverlayMarker[],
): ReadonlyMap<string, readonly GridOverlayMarker[]> => {
  const grouped = new Map<string, GridOverlayMarker[]>();

  for (const marker of markers) {
    const key = keyForPosition(marker);
    const existing = grouped.get(key);

    if (existing === undefined) {
      grouped.set(key, [marker]);
    } else {
      existing.push(marker);
    }
  }

  return grouped;
};

const featuresByCell = (
  state: GameState,
): ReadonlyMap<string, GridFeatureView> => {
  const grouped = new Map<string, GridFeatureView>();

  for (const feature of decorativeFeatures(state)) {
    grouped.set(keyForPosition(feature), feature);
  }

  return grouped;
};

const decorativeFeatures = (state: GameState): readonly GridFeatureView[] => {
  const opaque = asRecord(state.floor.geometry.opaque);
  const knowledge = asRecord(opaque?.knowledge);
  const features = knowledge?.decorativeFeatures;

  if (!Array.isArray(features)) {
    return [];
  }

  return features.flatMap((feature: SerializableRecord) => {
    const parsed = parseFeature(feature);
    return parsed === null ? [] : [parsed];
  });
};

const parseFeature = (feature: SerializableRecord): GridFeatureView | null => {
  const record = asRecord(feature);
  const id = stringValue(record?.id);
  const kind = stringValue(record?.kind);
  const name = stringValue(record?.name);
  const x = numberValue(record?.x);
  const y = numberValue(record?.y);

  if (id === null || kind === null || name === null || x === null || y === null) {
    return null;
  }

  return { id, kind, name, x, y };
};

const affordanceForLayer = (
  layer: GridLayer,
): { readonly badge: string; readonly shape: GridShape } => {
  switch (layer) {
    case "player":
      return { badge: "YOU", shape: "circle" };
    case "enemy":
      return { badge: "FOE", shape: "diamond" };
    case "npc":
      return { badge: "NPC", shape: "square" };
    case "item":
      return { badge: "ITM", shape: "dot" };
    case "trap":
      return { badge: "TRP", shape: "triangle" };
    case "terrain":
    case "empty":
      return { badge: "", shape: "none" };
  }
};

const labelForLayer = (layer: GridLayer, fog: GridFogState): string => {
  if (fog === "unseen") {
    return "unseen";
  }

  if (fog === "remembered") {
    return "remembered terrain";
  }

  switch (layer) {
    case "player":
      return "you";
    case "enemy":
      return "enemy";
    case "npc":
      return "npc";
    case "item":
      return "item";
    case "trap":
      return "revealed trap";
    case "terrain":
      return "terrain";
    case "empty":
      return "empty";
  }
};

const layerAt = (
  state: GameState,
  position: Position,
  glyph: string,
  fog: GridFogState,
  entities: readonly EntityInstance[],
): GridLayer => {
  if (fog === "unseen" || glyph === " ") {
    return "empty";
  }

  if (fog === "remembered") {
    return "terrain";
  }

  if (samePosition(state.player.position, position)) {
    return "player";
  }

  if (entities.some((entity) => entity.kind === "enemy")) {
    return "enemy";
  }

  if (entities.some((entity) => entity.kind === "npc")) {
    return "npc";
  }

  if (entities.some((entity) => entity.kind === "item")) {
    return "item";
  }

  if (entities.some((entity) => entity.kind === "trap") && glyph === GLYPH_TRAP) {
    return "trap";
  }

  return "terrain";
};

const entitiesByCell = (
  state: GameState,
): ReadonlyMap<string, readonly EntityInstance[]> => {
  const grouped = new Map<string, EntityInstance[]>();
  const entities = Object.values(state.entities).sort(compareEntities);

  for (const entity of entities) {
    const key = keyForPosition(entity.position);
    const existing = grouped.get(key);

    if (existing === undefined) {
      grouped.set(key, [entity]);
    } else {
      existing.push(entity);
    }
  }

  return grouped;
};

const compareEntities = (
  left: EntityInstance,
  right: EntityInstance,
): number => {
  const kindDelta = ENTITY_KIND_ORDER[left.kind] - ENTITY_KIND_ORDER[right.kind];

  if (kindDelta !== 0) {
    return kindDelta;
  }

  return compareEntityIds(left.id, right.id);
};

const compareEntityIds = (left: EntityId, right: EntityId): number => {
  const parsedLeft = parseEntityId(left);
  const parsedRight = parseEntityId(right);
  const kindOrder = parsedLeft.kind.localeCompare(parsedRight.kind);

  return kindOrder === 0
    ? parsedLeft.index - parsedRight.index
    : kindOrder;
};

const parseEntityId = (
  id: EntityId,
): { readonly kind: string; readonly index: number } => {
  const [kind, rawIndex] = id.split("#");

  return {
    kind: kind ?? "",
    index: Number.parseInt(rawIndex ?? "0", 10),
  };
};

const fogStatesForState = (
  state: GameState,
  width: number,
  height: number,
): readonly GridFogState[] => {
  const count = width * height;

  if (count <= 0) {
    return [];
  }

  const grid = gridFromState(state);

  if (
    grid === null ||
    grid.width !== width ||
    grid.height !== height ||
    grid.tiles.length !== count
  ) {
    return Array.from({ length: count }, () => "visible");
  }

  if (floorKnowledge(state).mapRevealed === true) {
    return Array.from({ length: count }, () => "visible");
  }

  const fog = fogFromState(state, grid) ?? defaultVisibleFog(grid);

  return fog.tiles.map((tile) => {
    switch (tile.state) {
      case "visible":
      case "remembered":
      case "unseen":
        return tile.state;
      default:
        return "unseen";
    }
  });
};

const effectsSinceLastRender = (
  state: GameState,
  previousCursor?: GridRenderCursor,
): ReadonlyMap<string, CellEffects> => {
  const cursor = cursorForState(state);
  const canDiff =
    previousCursor !== undefined &&
    previousCursor.runId === cursor.runId &&
    previousCursor.floorId === cursor.floorId &&
    previousCursor.logLength <= cursor.logLength;

  if (!canDiff) {
    return new Map();
  }

  const events = (state.log as readonly RuntimeLogEvent[]).slice(
    previousCursor.logLength,
  );

  if (events.length === 0) {
    return new Map();
  }

  const positionsByActorId = actorPositions(state);
  const effectsByPosition = new Map<string, MutableCellEffects>();

  events.forEach((event, eventIndex) => {
    applyPulseEvent(event, eventIndex, positionsByActorId, effectsByPosition);
    applyMovementEvent(event, positionsByActorId, effectsByPosition);
  });

  return new Map(
    [...effectsByPosition.entries()].map(([key, effects]) => [
      key,
      {
        pulses: effects.pulses,
        hitFlash: effects.hitFlash,
        motion: effects.motion,
      },
    ]),
  );
};

const applyPulseEvent = (
  event: RuntimeLogEvent,
  eventIndex: number,
  positionsByActorId: ReadonlyMap<string, Position>,
  effectsByPosition: Map<string, MutableCellEffects>,
): void => {
  const data = asRecord(event.data);
  const eventId = `${String(event.turn ?? "t")}:${String(event.type)}:${eventIndex}`;

  switch (event.type) {
    case "attack_hit": {
      const defenderId = stringValue(data?.defenderId);
      const damage = numberValue(data?.damage);

      if (defenderId !== null && damage !== null && damage > 0) {
        addPulseForActor(
          defenderId,
          positionsByActorId,
          effectsByPosition,
          {
            id: eventId,
            kind: "damage",
            text: `-${damage}`,
          },
        );
      }

    [...node.attributes].reduce<Record<string, string>>((attributes, attr) => {
      attributes[attr.name] = attr.value;
      return attributes;
    }, {})
  );
}

function findPlayer(
  cells: readonly GridCell[]
): { readonly x: number; readonly y: number } | null {
  const player = cells.find((cell) => cell.layer === "player");
  return player === undefined ? null : { x: player.x, y: player.y };
}

function findAdjacentEnemy(
  cells: readonly GridCell[],
  player: { readonly x: number; readonly y: number }
): { readonly x: number; readonly y: number } | null {
  for (const cell of cells) {
    if (cell.layer !== "enemy" || cell.fog !== "visible") {
      continue;
    }
    if (chebyshev(player, cell) <= 1) {
      return { x: cell.x, y: cell.y };
    }
  }
  return null;
}

function hasItemUnderfoot(
  cells: readonly GridCell[],
  player: { readonly x: number; readonly y: number }
): boolean {
  const cell = cells.find(
    (candidate) => candidate.x === player.x && candidate.y === player.y
  );
  return cell?.hasItem === true;
}

function isOnStairs(
  cells: readonly GridCell[],
  player: { readonly x: number; readonly y: number }
): boolean {
  const cell = cells.find(
    (candidate) => candidate.x === player.x && candidate.y === player.y
  );
  return cell?.terrain === "stairs_down";
}

function isOnHoard(
  cells: readonly GridCell[],
  player: { readonly x: number; readonly y: number }
): boolean {
  const cell = cells.find(
    (candidate) => candidate.x === player.x && candidate.y === player.y
  );
  return cell?.featureKind === "hoard";
}

function findTargetCells(
  cells: readonly GridCell[],
  predicate: (cell: GridCell) => boolean
): GridPosition[] {
  return cells
    .filter((cell) => cell.fog !== "unseen" && predicate(cell))
    .map((cell) => ({ x: cell.x, y: cell.y }));
}

function routeStep(
  player: GridPosition,
  targets: readonly GridPosition[],
  cells: readonly GridCell[]
): string | null {
  if (targets.length === 0) {
    return null;
  }

  const route = bfsRoute(player, targets, knownWalkableKeys(cells));
  return routeToDirectionKey(player, route);
}

function frontierStep(
  player: GridPosition,
  cells: readonly GridCell[],
  visited: ReadonlySet<string>
): string | null {
  const cellMap = cellsByKey(cells);
  const walkable = knownWalkableKeys(cells);
  const routeToFrontier = bfsRouteToPredicate(player, walkable, (position) => {
    const key = posKey(position.x, position.y);
    const cell = cellMap.get(key);
    return (
      cell !== undefined && !visited.has(key) && isFrontierCell(cell, cellMap)
    );
  });
  const route =
    routeToFrontier ??
    bfsRouteToPredicate(player, walkable, (position) => {
      const key = posKey(position.x, position.y);
      return (
        key !== posKey(player.x, player.y) &&
        !visited.has(key) &&
        cellMap.has(key)
      );
    });

  return routeToDirectionKey(player, route);
}

function boxedBreakKey(
  player: GridPosition,
  cells: readonly GridCell[],
  rng: () => number
): string {
  const cellMap = cellsByKey(cells);
  const candidates = DIRECTIONS.filter((direction) => {
    const delta = DIRECTION_DELTAS[direction];
    const cell = cellMap.get(posKey(player.x + delta.x, player.y + delta.y));
    return cell !== undefined && isWalkable(cell);
  });

  if (candidates.length === 0) {
    return ".";
  }

  return DIRECTION_KEYS[seededChoice(candidates, rng)];
}

function perpendicularDirections(
  direction: Direction | null
): readonly Direction[] {
  if (direction === null) {
    return ["north", "east", "south", "west"];
  }

  const source = DIRECTION_DELTAS[direction];
  return DIRECTIONS.filter((candidate) => {
    const delta = DIRECTION_DELTAS[candidate];
    return source.x * delta.x + source.y * delta.y === 0;
  });
}

function openAdjacentDirections(
  player: GridPosition,
  cells: readonly GridCell[],
  directions: readonly Direction[]
): Direction[] {
  const cellMap = cellsByKey(cells);
  return directions.filter((direction) => {
    const delta = DIRECTION_DELTAS[direction];
    const cell = cellMap.get(posKey(player.x + delta.x, player.y + delta.y));
    return cell !== undefined && isWalkable(cell);
  });
}

function adjacentDoorDirection(
  player: GridPosition,
  cells: readonly GridCell[],
  rng: () => number
): Direction | null {
  const cellMap = cellsByKey(cells);
  const doors = DIRECTIONS.filter((direction) => {
    const delta = DIRECTION_DELTAS[direction];
    const cell = cellMap.get(posKey(player.x + delta.x, player.y + delta.y));
    return (
      cell !== undefined && cell.fog !== "unseen" && cell.terrain === "door"
    );
  });

  return doors.length === 0 ? null : seededChoice(doors, rng);
}

function bfsRoute(
  start: GridPosition,
  targets: readonly GridPosition[],
  walkable: ReadonlySet<string>
): GridPosition[] | null {
  const targetKeys = new Set(
    targets.map((target) => posKey(target.x, target.y))
  );
  return bfsRouteToPredicate(start, walkable, (position) =>
    targetKeys.has(posKey(position.x, position.y))
  );
}

function bfsRouteToPredicate(
  start: GridPosition,
  walkable: ReadonlySet<string>,
  target: (position: GridPosition) => boolean
): GridPosition[] | null {
  if (target(start)) {
    return [start];
  }

  const queue: GridPosition[][] = [[start]];
  const seen = new Set([posKey(start.x, start.y)]);

  while (queue.length > 0) {
    const route = queue.shift();
    if (route === undefined) {
      break;
    }

    const current = route[route.length - 1];
    if (current === undefined) {
      continue;
    }

    for (const neighbor of neighbors(current)) {
      const key = posKey(neighbor.x, neighbor.y);
      if (seen.has(key) || !walkable.has(key)) {
        continue;
      }

      const nextRoute = [...route, neighbor];
      if (target(neighbor)) {
        return nextRoute;
      }

      seen.add(key);
      queue.push(nextRoute);
    }
  }

  return null;
}

function routeToDirectionKey(
  player: GridPosition,
  route: readonly GridPosition[] | null
): string | null {
  const next = route?.[1];
  return next === undefined ? null : directionKeyBetween(player, next);
}

function knownWalkableKeys(cells: readonly GridCell[]): Set<string> {
  return new Set(
    cells
      .filter((cell) => isWalkable(cell))
      .map((cell) => posKey(cell.x, cell.y))
  );
}

function cellsByKey(cells: readonly GridCell[]): Map<string, GridCell> {
  return new Map(cells.map((cell) => [posKey(cell.x, cell.y), cell]));
}

function isFrontierCell(
  cell: GridCell,
  cellMap: ReadonlyMap<string, GridCell>
): boolean {
  if (!isWalkable(cell)) {
    return false;
  }

  return neighbors(cell).some((neighbor) => {
    const next = cellMap.get(posKey(neighbor.x, neighbor.y));
    return next?.fog === "unseen";
  });
}

function neighbors(position: GridPosition): GridPosition[] {
  return DIRECTIONS.map((direction) => {
    const delta = DIRECTION_DELTAS[direction];
    return {
      x: position.x + delta.x,
      y: position.y + delta.y
    };
  });
}

function directionForKey(key: string | null): Direction | null {
  if (key === null) {
    return null;
  }

  return (
    DIRECTIONS.find((direction) => DIRECTION_KEYS[direction] === key) ?? null
  );
}

function directionKeyToward(
  from: { readonly x: number; readonly y: number },
  to: { readonly x: number; readonly y: number }
): string {
  return directionKeyBetween(from, to);
}

function directionKeyBetween(
  from: { readonly x: number; readonly y: number },
  to: { readonly x: number; readonly y: number }
): string {
  const dx = Math.sign(to.x - from.x);
  const dy = Math.sign(to.y - from.y);
  const direction = deltaToDirection(dx, dy);
  return DIRECTION_KEYS[direction];
}

function deltaToDirection(dx: number, dy: number): Direction {
  if (dx === 0 && dy === -1) return "north";
  if (dx === 1 && dy === -1) return "northeast";
  if (dx === 1 && dy === 0) return "east";
  if (dx === 1 && dy === 1) return "southeast";
  if (dx === 0 && dy === 1) return "south";
  if (dx === -1 && dy === 1) return "southwest";
  if (dx === -1 && dy === 0) return "west";
  return "northwest";
}

function isWalkable(cell: GridCell): boolean {
  if (cell.fog === "unseen") {
    return false;
  }

  if (cell.layer === "enemy" || cell.layer === "npc") {
    return false;
  }

  return !BLOCKED_TERRAIN.has(cell.terrain);
}

function markVisited(
  visitedByDepth: Map<number, Set<string>>,
  depth: number,
  player: GridPosition
): void {
  const bucket = visitedByDepth.get(depth) ?? new Set<string>();
  bucket.add(posKey(player.x, player.y));
  visitedByDepth.set(depth, bucket);
}

function samePosition(left: GridPosition, right: GridPosition): boolean {
  return left.x === right.x && left.y === right.y;
}

function posKey(x: number, y: number): string {
  return `${x},${y}`;
}

function chebyshev(
  left: { readonly x: number; readonly y: number },
  right: { readonly x: number; readonly y: number }
): number {
  return Math.max(Math.abs(left.x - right.x), Math.abs(left.y - right.y));
}

async function progressSignature(
  page: Page,
  shell: ShellSnapshot
): Promise<string> {
  const player = await readPlayerPosition(page);
  return JSON.stringify({
    depth: shell.depth,
    turn: shell.turn,
    panel: shell.panelMode,
    player
  });
}

