  EntityId,
  EntityInstance,
  GameState,
  PlayerItemStack,
  Position,
  SerializableRecord,
} from "../../engine/state/index.js";
import type { RunAction } from "../../engine/run/loop.js";
import type {
  BotKnownFeature,
  BotKnownItem,
  BotMemory,
  BotPolicyName,
  BotStateView,
} from "./types.js";

type BuildBotViewOptions = {
  readonly policyName: BotPolicyName;
  readonly memory?: BotMemory;
};

export const createEmptyBotMemory = (): BotMemory => ({
  visitedByDepth: new Map(),
  depthStartTurn: new Map(),
  knownFeaturesByDepth: new Map(),
  recentPositionsByDepth: new Map(),
});

export const createBotStateView = (
  state: GameState,
  options: BuildBotViewOptions,
): BotStateView => {
  const grid = gridFromState(state);
  const fog = grid === null ? null : (fogFromState(state, grid) ?? defaultVisibleFog(grid));
  const knowledge = floorKnowledge(state);
  const rememberedFeatures =
    options.memory?.knownFeaturesByDepth.get(state.run.depth) ?? [];
  const visibleFeatures = mergeFeatures([
    ...rememberedFeatures,
    ...readInspectableFeatures(state, fog),
  ]);
  const availableActions = availableRunActions(state, visibleFeatures);
  const inventory = state.player.inventory
    .filter((slot): slot is PlayerItemStack => slot !== null)
    .map((stack) => itemViewFromStack(state, stack, null));
  const equipment = {
    weapon:
      state.player.equipment.weapon === null
        ? null
        : itemViewFromStack(state, state.player.equipment.weapon, null, true),
    armor:
      state.player.equipment.armor === null
        ? null
        : itemViewFromStack(state, state.player.equipment.armor, null, true),
    charms: state.player.equipment.charms
      .filter((slot): slot is PlayerItemStack => slot !== null)
      .map((stack) => itemViewFromStack(state, stack, null, true)),
  };
  const visibleEntities = Object.values(state.entities)
    .filter((entity) => entityCellVisible(entity, fog, knowledge.mapRevealed === true))
    .sort((left, right) => left.id.localeCompare(right.id));
  const visited = positionsFromKeys(
    options.memory?.visitedByDepth.get(state.run.depth) ?? new Set(),
  );
  const depthStartedAt = options.memory?.depthStartTurn.get(state.run.depth) ?? state.run.turn;

  return {
    policyName: options.policyName,
    availableActions,
    rendered: render(state),
    run: {
      seed: state.run.seed,
      turn: state.run.turn,
      depth: state.run.depth,
      terminalStatus: state.run.terminalStatus,
    },
    floor: {
      width: grid?.width ?? 0,
      height: grid?.height ?? 0,
      turn: Math.max(0, state.run.turn - depthStartedAt),
    },
    player: {
      position: state.player.position,
      hp: {
        current: state.player.hp.current,
        max: state.player.hp.max,
        ratio: ratio(state.player.hp.current, state.player.hp.max),
      },
      fullness: {
        current: state.player.fullness.current,
        max: state.player.fullness.max,
        ratio: ratio(state.player.fullness.current, state.player.fullness.max),
      },
      level: state.player.level,
      statuses: state.player.statuses.map((status) => status.status),
      inventory,
      equipment,
    },
    map: {
      cells:
        grid === null || fog === null
          ? []
          : grid.tiles.flatMap((tile, index) => {
              const memory = fog.tiles[index];
              if (memory === undefined || hiddenCell(memory, knowledge.mapRevealed === true)) {
                return [];
              }

              return [
                {
                  position: {
                    x: index % grid.width,
                    y: Math.floor(index / grid.width),
                  },
                  terrain: tile.terrain,
                  door: tile.door,
                  visibility:
                    knowledge.mapRevealed === true || memory.state === "visible"
                      ? ("visible" as const)
                      : ("remembered" as const),
                },
              ];
            }),
      visited,
    },
    visible: {
      enemies: visibleEntities
        .filter((entity) => entity.kind === "enemy")
        .map((enemy) => ({
          id: enemy.id,
          name: enemy.definition.name,
          glyph: enemy.definition.glyph,
          position: enemy.position,
          hp: {
            current: enemy.currentHP,
            max: enemy.definition.stats.hp,
            ratio: ratio(enemy.currentHP, enemy.definition.stats.hp),
          },
          attack: enemy.definition.stats.attack,
          defense: enemy.definition.stats.defense,
          statuses: enemy.statuses.map((status) => status.status),
        })),
      npcs: visibleEntities
        .filter((entity) => entity.kind === "npc")
        .map((npc) => ({
          id: npc.id,
          name: npc.definition.name,
          position: npc.position,
        })),
      groundItems: visibleEntities
        .filter((entity) => entity.kind === "item")
        .map((item) =>
          itemViewFromStack(
            state,
            {
              itemInstanceId: item.id,
              definition: item.definition,
              quantity: item.quantity,
              identified: item.identified,
            },
            item.id,
            false,
            item.position,
          ),
        ),
      traps: visibleEntities
        .filter(
          (entity) =>
            entity.kind === "trap" &&
            isTrapRevealed(state, entity.id, entity.behaviorRuntime),
        )
        .map((trap) => ({
          id: trap.id,
          name: trap.definition.name,
          position: trap.position,
        })),
      features: visibleFeatures,
    },
    chooseIndex: (label, size) => {
      if (!Number.isSafeInteger(size) || size <= 0) {
        throw new RangeError("size must be a positive safe integer");
      }

      return createRng(state.rng.rootSeed)
        .fork(`bot:${options.policyName}`)
        .fork(`turn:${state.run.turn}`)
        .fork(label)
        .int(0, size - 1);
    },
  };
};

export const updateBotMemory = (
  memory: BotMemory,
  view: BotStateView,
): BotMemory => {
  const depth = view.run.depth;
  const positionKey = key(view.player.position);
  const visited = new Set(memory.visitedByDepth.get(depth) ?? []);
  visited.add(positionKey);

  const recent = [
    positionKey,
    ...(memory.recentPositionsByDepth.get(depth) ?? []).filter(
      (candidate) => candidate !== positionKey,
    ),
  ].slice(0, 16);
  const knownFeatures = mergeFeatures([
    ...(memory.knownFeaturesByDepth.get(depth) ?? []),
    ...view.visible.features,
  ]);
  const depthStartTurn = new Map(memory.depthStartTurn);
  if (!depthStartTurn.has(depth)) {
    depthStartTurn.set(depth, view.run.turn);
  }

  return {
    visitedByDepth: new Map(memory.visitedByDepth).set(depth, visited),
    depthStartTurn,
    knownFeaturesByDepth: new Map(memory.knownFeaturesByDepth).set(
      depth,
      knownFeatures,
    ),
    recentPositionsByDepth: new Map(memory.recentPositionsByDepth).set(depth, recent),
  };
};

const availableRunActions = (
  state: GameState,
  knownFeatures: readonly BotKnownFeature[],
): readonly RunAction[] => {
  const actions: RunAction[] = [...getAvailableActions(state)];

  if (
    knownFeatures.some(
      (feature) =>
        feature.kind === "hoard" &&
        feature.depth === state.run.depth &&
        samePosition(feature.position, state.player.position),
    )
  ) {
    actions.unshift({ kind: "take_hoard" });
  }

  return actions;
};

const itemViewFromStack = (
  state: GameState,
  stack: PlayerItemStack,
  entityId: EntityId | null,
  equipped = false,
  position: Position | null = null,
): BotKnownItem => {
  const knowledge = itemCardKnowledge(state, stack.definition, {
    itemInstanceId: stack.itemInstanceId,
    identified: stack.identified,
  });
  const bundle = knowledge.effectsKnown ? activeEffectBundle(stack.definition) : null;

  return {
    itemInstanceId: stack.itemInstanceId,
    entityId,
    definitionId: stack.definition.id,
    category: knowledge.category,
    displayName: knowledge.displayName,
    position,
    quantity: stack.quantity,
    identified: stack.identified,
    effectsKnown: knowledge.effectsKnown,
    effects: bundle?.effects ?? [],
    bonusKnown: knowledge.bonusKnown,
    bonus: knowledge.knownBonus,
    equipped,
  };
};

const readInspectableFeatures = (
  state: GameState,
  fog: FogMemory | null,
): readonly BotKnownFeature[] => {
  const knowledge = floorKnowledge(state);
  const records = readDecorativeFeatureRecords(knowledge);

  return records.flatMap((record) => {
    const feature = parseHoardFeature(record);
    if (feature === null) {
      return [];
    }

    if (
      fog !== null &&
      !cellKnown(fog, feature.position, knowledge.mapRevealed === true)
    ) {
      return [];
    }

    return [feature];
  });
};

const parseHoardFeature = (record: SerializableRecord): BotKnownFeature | null => {
  if (
    record.kind !== "hoard" ||
    typeof record.id !== "string" ||
    typeof record.name !== "string" ||
    typeof record.x !== "number" ||
    typeof record.y !== "number" ||
    typeof record.depth !== "number" ||
    !Number.isSafeInteger(record.x) ||
    !Number.isSafeInteger(record.y) ||
    !Number.isSafeInteger(record.depth)
  ) {
    return null;
  }

  return {
    id: record.id,
    kind: "hoard",
    name: record.name,
    position: { x: record.x, y: record.y },
    depth: record.depth,
  };
};

const readDecorativeFeatureRecords = (knowledge: {
  readonly [key: string]: unknown;
}): readonly SerializableRecord[] => {
  const records = knowledge.decorativeFeatures;
  if (!Array.isArray(records)) {
    return [];
  }

  return records.filter(
    (record): record is SerializableRecord =>
      record !== null && typeof record === "object" && !Array.isArray(record),
  );
};

const entityCellVisible = (
  entity: EntityInstance,
  fog: FogMemory | null,
  mapRevealed: boolean,
): boolean => {
  if (fog === null) {
    return true;
  }

  const memory = fog.tiles[idx(fog, entity.position)];
  if (memory === undefined) {
    return false;
  }

  return mapRevealed || memory.state === "visible";
};

const cellKnown = (
  fog: FogMemory,
  position: Position,
  mapRevealed: boolean,
): boolean => {
  const memory = fog.tiles[idx(fog, position)];
  return memory !== undefined && !hiddenCell(memory, mapRevealed);

import type { RunAction } from "../../../engine/run/loop.js";
import type { MoveDirection } from "../../../engine/turn/index.js";
import type { Position } from "../../../engine/state/index.js";
import type {
  BotKnownCell,
  BotKnownItem,
  BotStateView,
  BotVisibleEnemy,
} from "../types.js";

const DIRECTION_BY_DELTA = new Map<string, MoveDirection>([
  ["-1,-1", "northwest"],
  ["0,-1", "north"],
  ["1,-1", "northeast"],
  ["-1,0", "west"],
  ["1,0", "east"],
  ["-1,1", "southwest"],
  ["0,1", "south"],
  ["1,1", "southeast"],
]);

const WALKABLE_TERRAINS = new Set([
  "floor",
  "door",
  "water",
  "stairs_down",
  "entrance",
]);

export type RouteOptions = {
  readonly avoidKnownTraps?: boolean;
  readonly avoidEnemies?: boolean;
  readonly avoidRecent?: boolean;
};

export const actionKey = (action: RunAction): string =>
  JSON.stringify(action, Object.keys(action).sort());

export const hasAction = (view: BotStateView, action: RunAction): boolean =>
  view.availableActions.some((candidate) => actionKey(candidate) === actionKey(action));

export const actionOfKind = <Kind extends RunAction["kind"]>(
  view: BotStateView,
  kind: Kind,
): Extract<RunAction, { readonly kind: Kind }> | null =>
  (view.availableActions.find(
    (action): action is Extract<RunAction, { readonly kind: Kind }> =>
      action.kind === kind,
  ) ?? null);

export const adjacentEnemies = (
  view: BotStateView,
): readonly BotVisibleEnemy[] =>
  view.visible.enemies
    .filter((enemy) => chebyshev(view.player.position, enemy.position) <= 1)
    .sort(compareEnemies);

export const weakestEnemy = (
  enemies: readonly BotVisibleEnemy[],
): BotVisibleEnemy | null => [...enemies].sort(compareEnemies)[0] ?? null;

export const attackEnemy = (
  view: BotStateView,
  enemy: BotVisibleEnemy | null,
): RunAction | null => {
  if (enemy === null) {
    return null;
  }

  const action = { kind: "attack", targetId: enemy.id } as const;
  return hasAction(view, action) ? action : null;
};

export const retreatAction = (view: BotStateView): RunAction | null => {
  const moves = moveActions(view);
  if (moves.length === 0 || view.visible.enemies.length === 0) {
    return null;
  }

  const trapKeys = new Set(view.visible.traps.map((trap) => key(trap.position)));
  const candidates = moves
    .map((action) => {
      const destination = moveDestination(view.player.position, action.direction);
      const nearestEnemyDistance = Math.min(
        ...view.visible.enemies.map((enemy) => chebyshev(destination, enemy.position)),
      );
      const trapPenalty = trapKeys.has(key(destination)) ? 100 : 0;
      return { action, destination, score: nearestEnemyDistance - trapPenalty };
    })
    .filter((candidate) => candidate.score > 0)
    .sort((left, right) => {
      if (left.score !== right.score) {
        return right.score - left.score;
      }
      return key(left.destination).localeCompare(key(right.destination));
    });

  return candidates[0]?.action ?? null;
};

export const useHealingItem = (
  view: BotStateView,
  includeUnidentifiedDraught: boolean,
): RunAction | null => {
  const item = view.player.inventory.find((candidate) => {
    if (
      candidate.effectsKnown &&
      candidate.effects.some((effect) => effect.kind === "heal")
    ) {
      return true;
    }

    return includeUnidentifiedDraught && candidate.category === "draught";
  });

  return itemAction(view, item);
};

export const useFoodItem = (view: BotStateView): RunAction | null => {
  const item = view.player.inventory.find((candidate) => candidate.category === "food");
  return itemAction(view, item);
};

export const useEquipmentUpgrade = (view: BotStateView): RunAction | null => {
  const weapon = bestEquipmentCandidate(
    view.player.inventory.filter((item) => item.category === "weapon"),
    view.player.equipment.weapon,
  );
  const armor = bestEquipmentCandidate(
    view.player.inventory.filter((item) => item.category === "armor"),
    view.player.equipment.armor,
  );
  const charm = view.player.inventory.find((item) => item.category === "charm");

  return itemAction(view, weapon ?? armor ?? charm);
};

export const useRevealTool = (view: BotStateView): RunAction | null => {
  const item = view.player.inventory.find(
    (candidate) =>
      candidate.effectsKnown &&
      candidate.effects.some((effect) => effect.kind === "reveal"),
  );

  return itemAction(view, item);
};

export const useSafeUnidentifiedItem = (view: BotStateView): RunAction | null => {
  const safe = noNearbyEnemies(view, 4) && view.player.hp.ratio >= 0.7;
  if (!safe) {
    return null;
  }

  const item = view.player.inventory.find(
    (candidate) =>
      !candidate.effectsKnown &&
      candidate.category === "draught",
  );

  return itemAction(view, item);
};

export const pickupIfAvailable = (view: BotStateView): RunAction | null =>
  actionOfKind(view, "pickup");

export const takeHoardIfAvailable = (view: BotStateView): RunAction | null =>
  actionOfKind(view, "take_hoard");

export const descendIfAvailable = (view: BotStateView): RunAction | null =>
  actionOfKind(view, "descend");

export const abortIfFloorBudgetExceeded = (
  view: BotStateView,
  budgetTurns: number,
): RunAction | null =>
  view.floor.turn > budgetTurns ? actionOfKind(view, "abort") : null;

export const moveTowardNearestItem = (
  view: BotStateView,
  maxDistance?: number,
): RunAction | null => {
  const route = nearestRoute(
    view,
    view.visible.groundItems
      .map((item) => item.position)
      .filter((position): position is Position => position !== null),
    { avoidKnownTraps: true, avoidEnemies: true },
  );

  if (route === null || (maxDistance !== undefined && route.length - 1 > maxDistance)) {
    return null;
  }

  return actionFromRoute(view, route);
};

export const moveTowardNearestEnemy = (
  view: BotStateView,
  maxDistance?: number,
): RunAction | null => {
  const targets = view.visible.enemies.flatMap((enemy) =>
    walkableNeighbors(view, enemy.position),
  );
  const route = nearestRoute(view, targets, {
    avoidKnownTraps: true,
    avoidEnemies: true,
  });

  if (route === null || (maxDistance !== undefined && route.length - 1 > maxDistance)) {
    return null;
  }

  return actionFromRoute(view, route);
};

export const moveTowardStairs = (view: BotStateView): RunAction | null => {
  const conservative = nearestRoute(
    view,
    view.map.cells
      .filter((cell) => cell.terrain === "stairs_down")
      .map((cell) => cell.position),
    { avoidKnownTraps: true, avoidEnemies: true },
  );
  const route =
    conservative ??
    nearestRoute(
      view,
      view.map.cells
        .filter((cell) => cell.terrain === "stairs_down")
        .map((cell) => cell.position),
      { avoidKnownTraps: true, avoidEnemies: false },
    );

  return route === null ? null : actionFromRoute(view, route);
};

export const moveTowardHoard = (view: BotStateView): RunAction | null => {
  const targets = view.visible.features
    .filter((feature) => feature.kind === "hoard" && feature.depth === view.run.depth)
    .map((feature) => feature.position);
  const conservative = nearestRoute(
    view,
    targets,
    { avoidKnownTraps: true, avoidEnemies: true },
  );
  const route =
    conservative ??
    nearestRoute(view, targets, {
      avoidKnownTraps: true,
      avoidEnemies: false,
    });

  return route === null ? null : actionFromRoute(view, route);
};

export const exploreUnvisited = (
  view: BotStateView,
  budgetTurns: number,
): RunAction | null => {
  if (view.floor.turn >= budgetTurns) {
    return null;
  }

  const visitedKeys = new Set(view.map.visited.map(key));
  const route = nearestRoute(
    view,
    view.map.cells
      .filter((cell) => isWalkable(cell) && !visitedKeys.has(key(cell.position)))
      .map((cell) => cell.position),
    { avoidKnownTraps: true, avoidEnemies: true, avoidRecent: true },
  );

  return route === null ? null : actionFromRoute(view, route);
};

export const fallbackAction = (view: BotStateView): RunAction => {
  const productive =
    takeHoardIfAvailable(view) ??
    descendIfAvailable(view) ??
    pickupIfAvailable(view) ??
    attackEnemy(view, weakestEnemy(adjacentEnemies(view))) ??
    moveTowardStairs(view);

  if (productive !== null) {
    return productive;
  }

  return actionOfKind(view, "wait") ?? { kind: "abort" };
};

export const noNearbyEnemies = (view: BotStateView, distance: number): boolean =>
  view.visible.enemies.every(
    (enemy) => chebyshev(view.player.position, enemy.position) > distance,
  );

export const chebyshev = (left: Position, right: Position): number =>
  Math.max(Math.abs(left.x - right.x), Math.abs(left.y - right.y));

const itemAction = (
  view: BotStateView,
  item: BotKnownItem | undefined | null,
): RunAction | null => {
  if (item?.itemInstanceId === null || item?.itemInstanceId === undefined) {
    return null;
  }

  const action = { kind: "use_item", itemId: item.itemInstanceId } as const;
  return hasAction(view, action) ? action : null;
};

const bestEquipmentCandidate = (
  carried: readonly BotKnownItem[],
  equipped: BotKnownItem | null,
): BotKnownItem | null => {
  const sorted = [...carried].sort((left, right) => {
    const leftBonus = left.bonusKnown ? (left.bonus ?? 0) : 1;
    const rightBonus = right.bonusKnown ? (right.bonus ?? 0) : 1;
    return rightBonus - leftBonus || left.definitionId.localeCompare(right.definitionId);
  });
  const best = sorted[0];

import type {
  InspectCard,
  InventoryActionView,
  InventoryEntry,
  InventoryView,
} from "../model";

type InventoryPanelProps = {
  readonly view: InventoryView;
  readonly selectedEntry: InventoryEntry | null;
  readonly selectedEntryIndex: number;
  readonly selectedActionIndex: number;
  readonly actions: readonly InventoryActionView[];
  readonly card: InspectCard | null;
  readonly throwPrompt: boolean;
  readonly onSelectEntry: (index: number) => void;
  readonly onSelectAction: (index: number) => void;
  readonly onRunAction: (index: number) => void;
};

export function InventoryPanel({
  view,
  selectedEntry,
  selectedEntryIndex,
  selectedActionIndex,
  actions,
  card,
  throwPrompt,
  onSelectEntry,
  onSelectAction,
  onRunAction,
}: InventoryPanelProps) {
  const allEntries = [...view.slots, ...view.equipment];

  return (
    <div
      className="grid h-full min-h-0 grid-rows-[auto_minmax(0,1fr)_auto] gap-3 p-3 text-left"
      data-testid="inventory-panel"
    >
      <div>
        <h2 className="text-sm font-semibold normal-case tracking-normal text-gg-text">
          Inventory
        </h2>
        <p className="text-xs normal-case tracking-normal text-gg-muted">
          {filledSlots(view.slots)}/16 slots
        </p>
      </div>

      <div className="grid min-h-0 grid-cols-[minmax(0,1fr)_minmax(8rem,0.8fr)] gap-3">
        <div className="min-h-0 overflow-auto">
          <div className="grid grid-cols-4 gap-1" aria-label="Inventory slots">
            {view.slots.map((entry) => {
              const index = allEntries.findIndex((candidate) => candidate.id === entry.id);
              return (
                <button
                  className={slotClass(index === selectedEntryIndex, entry.empty)}
                  data-inventory-slot={entry.index}
                  key={entry.id}
                  type="button"
                  onClick={() => onSelectEntry(index)}
                >
                  <span className="text-[0.62rem] text-gg-muted">
                    {entry.index + 1}
                  </span>
                  <span className="truncate">{entry.label}</span>
                </button>
              );
            })}
          </div>

          <div className="mt-3 space-y-1" aria-label="Equipment slots">
            {view.equipment.map((entry) => {
              const index = allEntries.findIndex((candidate) => candidate.id === entry.id);
              return (
                <button
                  className={equipmentClass(index === selectedEntryIndex)}
                  data-equipment-slot={entry.id}
                  key={entry.id}
                  type="button"
                  onClick={() => onSelectEntry(index)}
                >
                  {entry.label}
                </button>
              );
            })}
          </div>
        </div>

        <SelectionCard card={card} selectedEntry={selectedEntry} />
      </div>

      <div className="border-t border-gg-border pt-2">
        {throwPrompt ? (
          <div
            className="rounded border border-amber-300/35 bg-amber-300/10 px-2 py-1 text-xs font-semibold normal-case tracking-normal text-amber-100"
            data-throw-direction-prompt="true"
          >
            Throw direction
          </div>
        ) : null}
        <div className="mt-2 flex flex-wrap gap-1" aria-label="Inventory actions">
          {actions.length === 0 ? (
            <span className="text-xs normal-case tracking-normal text-gg-muted">
              No actions.
            </span>
          ) : (
            actions.map((action, index) => (
              <button
                className={actionClass(
                  index === selectedActionIndex,
                  action.enabled,
                )}
                data-action-id={action.id}
                data-disabled-reason={action.reason ?? ""}
                disabled={!action.enabled}
                key={action.id}
                type="button"
                title={action.reason ?? action.label}
                onClick={() => {
                  onSelectAction(index);
                  onRunAction(index);
                }}
              >
                {index + 1}. {action.label}
                {action.enabled ? null : (
                  <span className="ml-1 text-amber-200">({action.reason})</span>
                )}
              </button>
            ))
          )}
        </div>
      </div>
    </div>
  );
}

function SelectionCard({
  card,
  selectedEntry,
}: {
  readonly card: InspectCard | null;
  readonly selectedEntry: InventoryEntry | null;
}) {
  if (card === null || selectedEntry?.stack === null) {
    return (
      <div className="rounded border border-gg-border p-2 text-xs normal-case tracking-normal text-gg-muted">
        Empty slot
      </div>
    );
  }

  return (
