const openDoor = (
  state: GameState,
  grid: TileGrid,
  at: Position,
  direction: MoveDirection,
): ActionResolverResult => {
  const openedGrid = withTile(grid, at, createTile(Terrain.Door, "open"));

  return {
    state: {
      ...state,
      floor: {
        ...state.floor,
        geometry: createFloorGeometrySlot(state.floor.geometry.refId, openedGrid),
      },
    },
    events: [
      movementEvent(state, "door_opened", {
        actorId: PLAYER_ACTOR_ID,
        at,
        direction,
      }),
    ],
  };
};

const withPlayerPosition = (
  state: GameState,
  position: Position,
): GameState => ({
  ...state,
  player: {
    ...state.player,
    position,
  },
});

const blockedTerrainReason = (tile: Tile): string => {
  if (tile.terrain === Terrain.Wall) {
    return "A wall blocks the way.";
  }

  return `Terrain ${tile.terrain} blocks the way.`;
};

const isClosedDoor = (tile: Tile): boolean =>
  tile.terrain === Terrain.Door && tile.door === "closed";

const actorAt = (
  state: GameState,
  position: Position,
): ActorOccupant | null =>
  actors(state).find((actor) => samePosition(actor.position, position)) ?? null;

const actors = (state: GameState): readonly ActorOccupant[] => [
  {
    kind: "player",
    id: PLAYER_ACTOR_ID,
    position: state.player.position,
  },
  ...Object.values(state.entities)
    .filter(isActorEntity)
    .sort((a, b) => a.id.localeCompare(b.id)),
];

const actorOccupancyViolation = (state: GameState): string | null => {
  const occupied = new Map<string, ActorOccupant>();

  for (const actor of actors(state)) {
    const key = positionKey(actor.position);
    const previous = occupied.get(key);

    if (previous !== undefined) {
      return `actor occupancy invariant violated at (${actor.position.x}, ${actor.position.y}) by ${actor.id} and ${previous.id}`;
    }

    occupied.set(key, actor);
  }

export const checkActionLegality = (
  state: GameState,
  action: PlayerAction,
): ActionLegality => {
  if (state.run.terminalStatus !== "ACTIVE") {
    return illegal(`run is terminal (${state.run.terminalStatus})`);
  }

  switch (action.kind) {
    case "move":
      return checkMoveAction(state, action);
    case "attack":
      return checkAttackAction(state, action);
    case "use_item":
      return checkUseItemAction(state, action);
    case "pickup":
      return checkPickupAction(state);
    case "talk":
      return checkTalkAction(state, action);
    case "wait":
      return LEGAL_ACTION;
    case "descend":
      return checkDescendAction(state);
    case "inspect":
      return checkInspectAction(state, action);
    case "abort":
      return LEGAL_ACTION;
  }
};

export const getAvailableActions = (state: GameState): readonly PlayerAction[] => {
  if (state.run.terminalStatus !== "ACTIVE") {
    return [];
  }

  const actions: PlayerAction[] = [];

  for (const { direction } of MOVE_DIRECTIONS) {
    const action = { kind: "move", direction } as const;
    pushIfLegal(actions, state, action);
  }

  for (const entity of sortedEntities(state)) {
    if (entity.kind === "enemy") {
      pushIfLegal(actions, state, {
        kind: "attack",
        targetId: entity.id,
      });
    }
  }

  for (const item of carriedItems(state.player.inventory)) {
    pushIfLegal(actions, state, {
      kind: "use_item",
      itemId: item.itemInstanceId,
    });
  }

  pushIfLegal(actions, state, { kind: "pickup" });

  for (const entity of sortedEntities(state)) {
    if (entity.kind === "npc") {
      pushIfLegal(actions, state, {
        kind: "talk",
        npcId: entity.id,
      });
    }
  }

  pushIfLegal(actions, state, { kind: "wait" });
  pushIfLegal(actions, state, { kind: "descend" });
  actions.push(...availableInspectActions(state));
  pushIfLegal(actions, state, { kind: "abort" });

  return actions;
};

export const destinationForMove = (
  origin: Position,
  direction: MoveDirection,
): Position => {
  const offset = offsetForDirection(direction);

  return {
    x: origin.x + offset.x,
    y: origin.y + offset.y,
  };
};

export const gridFromState = (state: GameState): TileGrid | null => {
  const opaque = state.floor.geometry.opaque;

  if (!isTileGridRecord(opaque)) {
    return null;
  }

  return opaque as unknown as TileGrid;
};

const checkMoveAction = (
  state: GameState,
  action: MoveAction,
): ActionLegality => {
  const grid = gridFromState(state);

  if (grid === null) {
    return illegal("floor geometry is not loaded");
  }

  const destination = destinationForMove(state.player.position, action.direction);

  if (!inBounds(grid, destination)) {
    return illegal(
      `move ${action.direction} leaves the map at (${destination.x}, ${destination.y})`,
    );
  }

  const tile = getTile(grid, destination);

  if (!isWalkableTile(tile)) {
    return illegal(`terrain ${tile.terrain} blocks movement`);
  }

  return LEGAL_ACTION;
};

const checkAttackAction = (
  state: GameState,
  action: AttackAction,
): ActionLegality => {
  const target = state.entities[action.targetId];

  if (target === undefined) {
    return illegal(`attack target ${action.targetId} does not exist`);
  }

  if (target.kind !== "enemy") {
    return illegal(`attack target ${action.targetId} is not an enemy`);
  }

  if (!isAdjacentToPlayer(state, target.position)) {
    return illegal(`attack target ${action.targetId} is not adjacent`);
  }

  return LEGAL_ACTION;
};

export const Terrain = {
  Floor: "floor",
  Wall: "wall",
  Door: "door",
  Water: "water",
  StairsDown: "stairs_down",
  Entrance: "entrance",
} as const;

export type TerrainKind = (typeof Terrain)[keyof typeof Terrain];

export type DoorState = "open" | "closed";

export type Tile = {
  readonly terrain: TerrainKind;
  readonly door: DoorState | null;
};

export const TERRAIN_KINDS = [
  Terrain.Floor,
  Terrain.Wall,
  Terrain.Door,
  Terrain.Water,
  Terrain.StairsDown,
  Terrain.Entrance,
] as const satisfies readonly TerrainKind[];

export const TERRAIN_WALKABLE = {
  [Terrain.Floor]: true,
  [Terrain.Wall]: false,
  [Terrain.Door]: true,
  [Terrain.Water]: true,
  [Terrain.StairsDown]: true,
  [Terrain.Entrance]: true,
} as const satisfies Record<TerrainKind, boolean>;

export const TERRAIN_TRANSPARENT = {
  [Terrain.Floor]: true,
  [Terrain.Wall]: false,
  [Terrain.Door]: false,
  [Terrain.Water]: true,
  [Terrain.StairsDown]: true,
  [Terrain.Entrance]: true,
} as const satisfies Record<TerrainKind, boolean>;

export const createTile = (
  terrain: TerrainKind,
  door: DoorState | null = null,
): Tile => ({
  terrain,
  door: terrain === Terrain.Door ? (door ?? "closed") : null,
});

export const cloneTile = (tile: Tile): Tile => ({
  terrain: tile.terrain,
  door: tile.terrain === Terrain.Door ? (tile.door ?? "closed") : null,
});

export const isWalkableTerrain = (terrain: TerrainKind): boolean =>
  TERRAIN_WALKABLE[terrain];

export const isTransparentTerrain = (terrain: TerrainKind): boolean =>
  TERRAIN_TRANSPARENT[terrain];

export const isWalkableTile = (tile: Tile): boolean =>
  TERRAIN_WALKABLE[tile.terrain];

export const isTransparentTile = (tile: Tile): boolean => {
  if (tile.terrain === Terrain.Door) {
    return tile.door === "open";
  }

  return TERRAIN_TRANSPARENT[tile.terrain];
};

